import{_ as r,o as a,c as t,a2 as s}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Requirements","description":"","frontmatter":{},"headers":[],"relativePath":"server/requirements.md","filePath":"server/requirements.md"}'),o={name:"server/requirements.md"};function n(i,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h1><p>Tragwerk deploys your PHP applications to your own server. You bring the machine and SSH access; Tragwerk installs and manages everything else — Docker, the Traefik reverse proxy, and the generated per-application container stack.</p><h2 id="server-and-ssh-access" tabindex="-1">Server and SSH access <a class="header-anchor" href="#server-and-ssh-access" aria-label="Permalink to &quot;Server and SSH access&quot;">​</a></h2><p>The only hard requirement is a server you can reach over <strong>SSH</strong>. Tragwerk connects to the server, installs the Docker environment, and from then on drives all provisioning and deploys remotely.</p><ul><li>A reachable host (public IP or hostname) with an open SSH port.</li><li>A user that can run Docker (typically <code>root</code>, or a sudo-capable user).</li><li>Authentication via an SSH key or password — stored as a <a href="/app/registries-credentials">credential</a>.</li></ul><p>You can register any number of servers and run multiple applications on each. See <a href="/server/servers">Servers</a> to add one.</p><h2 id="docker-support-matrix" tabindex="-1">Docker support matrix <a class="header-anchor" href="#docker-support-matrix" aria-label="Permalink to &quot;Docker support matrix&quot;">​</a></h2><p>Tragwerk runs everything on the server through Docker and Docker Compose. The officially supported targets are therefore <strong>whatever Docker itself supports</strong>.</p><p>Refer to the official Docker Engine install matrix for supported distributions and versions: <a href="https://docs.docker.com/engine/install/" target="_blank" rel="noreferrer">https://docs.docker.com/engine/install/</a>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You do not need to install Docker yourself. Tragwerk&#39;s <a href="/server/server-setup">server setup</a> installs and configures the Docker environment for you over SSH.</p></div><h2 id="what-tragwerk-installs-and-manages" tabindex="-1">What Tragwerk installs and manages <a class="header-anchor" href="#what-tragwerk-installs-and-manages" aria-label="Permalink to &quot;What Tragwerk installs and manages&quot;">​</a></h2><p>During <a href="/server/server-setup">server setup</a> Tragwerk provisions:</p><ul><li><strong>Docker</strong> and Docker Compose on the host.</li><li><strong>Traefik</strong> as a host-level reverse proxy that terminates TLS and routes public traffic to your applications.</li><li>A shared external Docker network, <code>tragwerk-net</code>, that every application container joins so Traefik can reach it.</li></ul><p>Per application it then generates a <code>Dockerfile.{appSlug}</code> and a <code>docker-compose.yml</code> and runs the resulting containers. See <a href="/server/architecture-on-host">Architecture on the Host</a>.</p><h2 id="sizing-guidance" tabindex="-1">Sizing guidance <a class="header-anchor" href="#sizing-guidance" aria-label="Permalink to &quot;Sizing guidance&quot;">​</a></h2><p>Sizing depends entirely on your workload, but as a generic starting point:</p><ul><li><strong>CPU/RAM:</strong> A small app comfortably runs on 1–2 vCPU and 1–2 GB RAM. Add headroom for each additional application, database, or service container, plus the memory needed for image builds.</li><li><strong>Disk:</strong> Plan for your application image(s), build cache, and any persistent <a href="/config/mounts">mounts</a> and service volumes. Image builds and the registry cache can grow over time.</li></ul><p>Scale up as you add applications — multiple apps coexist on one server, so a larger server lets you consolidate more environments.</p><h2 id="dns-and-domains" tabindex="-1">DNS and domains <a class="header-anchor" href="#dns-and-domains" aria-label="Permalink to &quot;DNS and domains&quot;">​</a></h2><p>Public routing and automatic TLS (Let&#39;s Encrypt via Traefik) require working DNS:</p><ul><li>Point an <strong>A/AAAA record</strong> for each domain (or a wildcard) at your server&#39;s IP.</li><li>Each application is routed by host/subdomain, so distinct apps on the same server use distinct hostnames.</li><li>Valid public DNS is also a prerequisite for Let&#39;s Encrypt certificate issuance.</li></ul><p>See <a href="/app/domains">Domains</a> for configuring hostnames per environment.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/server/servers">Servers</a></li><li><a href="/server/server-setup">Server Setup</a></li><li><a href="/server/architecture-on-host">Architecture on the Host</a></li><li><a href="/app/domains">Domains</a></li></ul>',24)])])}const m=r(o,[["render",n]]);export{h as __pageData,m as default};
